def normalize(raw) {
  return {
    previousLevel: raw.previousLevel,
    currentLevel: raw.currentLevel
  };
}

val raw = {
  previousLevel: "low",
  currentLevel: "high"
};

val normalized = normalize(raw);
if (normalized.currentLevel == "high") {
  print("alert");
} else {
  print("ok");
}
